// Time range in seconds
const startTime = new Date(metricsStartTime.outputs).getTime();
const endTime = new Date(metricsEndTime.outputs).getTime();
const timeRangeInSeconds = (endTime - startTime) / 1000;

// Aim for ~75 data points (middle of 50-100 range)
const targetDataPoints = 200;

// Calculate optimal period in seconds
const optimalPeriod = Math.ceil(timeRangeInSeconds / targetDataPoints);

// Round up to nearest supported CloudWatch period
// CloudWatch periods must be multiples of 60 seconds
const roundedPeriod = Math.ceil(optimalPeriod / 60) * 60;

return roundedPeriod;})()}

