${{
    "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
    "data": {
        values: getMetricDataForCluster.outputs.rds_cpu_usage.timeSeriesData
    },
    "autosize": {
        "type": "fit",
        "contains": "padding"
    },
    "encoding": {
        "x": {
            "field": "date",
            "type": "temporal",
            title: "Date"
        }
    },
    "transform": [
    {
      "calculate": "datum.value / 100",
      "as": "value"
    }
  ],
    "layer": [
        {
            "encoding": {
                "y": {
                    "field": "value",
                    "type": "quantitative",
                    title: "CPU Utilization"
                }
            },
            "layer": [
                {
                    "mark": "line"
                },
                {
                    "transform": [
                        {
                            "filter": {
                                "param": "hover",
                                "empty": false
                            }
                        }
                    ],
                    "mark": "point"
                }
            ]
        },
        {
            "mark": "rule",
            "encoding": {
                "opacity": {
                    "condition": {
                        "value": 0.3,
                        "param": "hover",
                        "empty": false
                    },
                    "value": 0
                },
                "tooltip": [
                    {
                        "field": "value",
                        "type": "quantitative",
                         title: "CPU Usage",
                         format: ".0%"
                    },
                    {
                        field: "date",
                        type: "temporal",
                        title: "Date",
                    }
                ]
            },
            "params": [
                {
                    "name": "hover",
                    "select": {
                        "type": "point",
                        "fields": [
                            "date"
                        ],
                        "nearest": true,
                        "on": "pointerover",
                        "clear": "pointerout"
                    }
                }
            ]
        }
    ],
    config: {
        legend: {
            disable: true
        }
    }
}}

